import numpy as np

def predict(frame, action):
    out = frame.copy()
    H, W = out.shape
    BG, TRAIL, WALL, OBJ, HOLE = 2, 1, 4, 14, 0
    deltas = {1: (-3, 0), 2: (3, 0), 3: (0, -3), 4: (0, 3)}  # up/down/left/right, by object size

    # Locate the object: its center is the 0-cell (rows<63) ringed by 14s.
    center, best = None, None
    for (r, c) in np.argwhere(out[:63, :] == HOLE):
        if 1 <= r <= 61 and 1 <= c <= W - 2:
            n14 = int((out[r-1:r+2, c-1:c+2] == OBJ).sum())
            if best is None or n14 > best[0]:
                best = (n14, r, c)
    if best is not None and best[0] >= 4:
        center = (best[1], best[2])

    if center is not None and action in deltas:
        cr, cc = center
        dr, dc = deltas[action]
        nr = max(1, min(H - 2, cr + dr))
        nc = max(1, min(W - 2, cc + dc))
        old = {(cr+i, cc+j) for i in (-1,0,1) for j in (-1,0,1)}
        new = {(nr+i, nc+j) for i in (-1,0,1) for j in (-1,0,1)}

        # Vacated cells reveal the static layer beneath: wall (4) if a wall
        # line passes through, otherwise the object's trail (1).
        for (r, c) in old - new:
            is_wall = ((cr-2 >= 0 and frame[cr-2, c] == WALL) or
                       (cr+2 < H and frame[cr+2, c] == WALL) or
                       (cc-2 >= 0 and frame[r, cc-2] == WALL) or
                       (cc+2 < W and frame[r, cc+2] == WALL))
            out[r, c] = WALL if is_wall else TRAIL

        # Draw object (ring of 14 + center hole) on top of whatever is there.
        for (r, c) in new:
            out[r, c] = OBJ
        out[nr, nc] = HOLE

    # Step counter on row 63 marches right->left, one new 0 per move.
    if action in deltas:
        z = np.where(out[63, :] == 0)[0]
        if len(z) == 0:
            out[63, W - 1] = 0
        elif int(z.min()) - 1 >= 0:
            out[63, int(z.min()) - 1] = 0

    return out
